mapper.update:
update ORDERS
Set
    FINAL_PRICE = #{finalPrice},
    POINT_AMOUNT = #{pointAmount}
Where 1 = 1
And id = #{orderId}

mapper.select:
SELECT ot.id AS ticket_id, ot.ticket_number AS ticket_number, ot.partner_order_code AS partner_order_code, ot.ticket_used AS ticket_used, ot.status AS status
FROM order_tickets ot JOIN order_items oi ON oi.id = ot.order_item_id JOIN orders o ON o.id = oi.order_id
WHERE o.order_number = #{orderNumber}

mapper.update:
UPDATE product_option_values
SET stock = stock - #{quantity},
    updated_at = NOW()
WHERE id = #{optionValueId}
AND stock >= #{quantity}
